#include <iostream>

void fizzbuzz(int count)
{
	for (int i{ 1 }; i <= count; ++i)
	{
		if (i % 3 == 0 && i % 5 == 0)
		{
			std::cout << "fizzbuzz\n";
		}
		else if (i % 3 == 0)
		{
			std::cout << "fizz\n";
		}
		else if (i % 5 == 0)
		{
			std::cout << "buzz\n";
		}
		else
		{
			std::cout << i << '\n';
		}
	} // end for loop
}

int main()
{
	fizzbuzz(15);

	return 0;
