{
    for (int x{ 0 }, y{ 9 }; x < 10; ++x, --y)
        std::cout << x << ' ' << y << '\n';

    return 0;
}This loop defines and initializes two new variables:xandy. It iteratesxover the range0to9, and after each iterationxis incremented andyis decremented.This program produces the result:0 9
